+
+  @override
+  bool operator ==(Object other) =>
+      identical(this, other) ||
+      other is StreamResolveParams &&
+          imdbId == other.imdbId &&
+          season == other.season &&
+          episode == other.episode;
+
+  @override
+  int get hashCode => imdbId.hashCode ^ (season ?? 0).hashCode ^ (episode ?? 0).hashCode;
+}
